'use client';

import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState } from 'react';
import { ChevronLeft, ChevronRight, X } from 'lucide-react';
import Image from 'next/image';

interface ProjectOverviewModalProps {
  isOpen: boolean;
  onClose: () => void;
  project: {
    title: string;
    description: string;
    techStack: string[];
    acheivements: string[];
    screenShots: string[];
  };
}

export default function ProjectOverviewModal({
  isOpen,
  onClose,
  project,
}: ProjectOverviewModalProps) {
  const [index, setIndex] = useState(0);

  // ✅ LOCK BACKGROUND SCROLL
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }

    return () => {
      document.body.style.overflow = '';
    };
  }, [isOpen]);

  if (!project) return null;

  const next = () =>
    setIndex((prev) => (prev + 1) % project.screenShots.length);
  const prev = () =>
    setIndex(
      (prev) =>
        (prev - 1 + project.screenShots.length) % project.screenShots.length,
    );

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          className='fixed inset-0 z-50 flex items-center justify-center'
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
        >
          {/* 🔥 BACKDROP */}
          <div
            className='absolute inset-0 bg-black/60 backdrop-blur-sm'
            onClick={onClose}
          />

          {/* 🔥 MODAL */}
          <motion.div
            initial={{ scale: 0.95, y: 40, opacity: 0 }}
            animate={{ scale: 1, y: 0, opacity: 1 }}
            exit={{ scale: 0.96, y: 20, opacity: 0 }}
            transition={{ type: 'spring', stiffness: 260, damping: 22 }}
            className='relative z-10 w-full max-w-3xl h-[85vh] bg-white rounded-2xl shadow-xl flex flex-col overflow-hidden'
            onClick={(e) => e.stopPropagation()}
          >
            {/* HEADER */}
            <div className='flex justify-between items-center px-6 py-4 border-b'>
              <h2 className='text-xl font-semibold'>{project.title}</h2>
              <button onClick={onClose}>
                <X />
              </button>
            </div>

            {/* CONTENT (SCROLL ONLY HERE) */}
            <div className='flex-1 overflow-y-auto px-6 py-5 space-y-6'>
              {/* DESCRIPTION */}
              <p className='text-gray-600 leading-relaxed'>
                {project.description}
              </p>

              {/* TECH STACK */}
              <div>
                <h3 className='font-semibold mb-2'>Tech Stack</h3>
                <div className='flex flex-wrap gap-2'>
                  {project.techStack.map((tech, i) => (
                    <span
                      key={i}
                      className='px-3 py-1 bg-gray-100 rounded-full text-sm'
                    >
                      {tech}
                    </span>
                  ))}
                </div>
              </div>

              {/* ACHIEVEMENTS */}
              <div>
                <h3 className='font-semibold mb-2'>Achievements</h3>
                <ul className='list-disc list-inside text-gray-600'>
                  {project.acheivements.map((a, i) => (
                    <li key={i}>{a}</li>
                  ))}
                </ul>
              </div>

              {/* 🔥 IMAGE SLIDER */}
              {project.screenShots.length > 0 && (
                <div className='relative'>
                  <Image
                    src={project.screenShots[index]}
                    alt='screenshot'
                    width={800}
                    height={400}
                    className='w-full h-64 object-cover rounded-xl'
                  />

                  {/* LEFT */}
                  <button
                    onClick={prev}
                    className='absolute left-2 top-1/2 -translate-y-1/2 bg-white p-2 rounded-full shadow'
                  >
                    <ChevronLeft />
                  </button>

                  {/* RIGHT */}
                  <button
                    onClick={next}
                    className='absolute right-2 top-1/2 -translate-y-1/2 bg-white p-2 rounded-full shadow'
                  >
                    <ChevronRight />
                  </button>
                </div>
              )}
            </div>

            {/* FOOTER */}
            <div className='px-6 py-4 border-t text-right'>
              <button
                onClick={onClose}
                className='px-4 py-2 bg-black text-white rounded-lg'
              >
                Close
              </button>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
